class Solution {
public:
    int lca(int n, std::vector<std::vector<int>> adj, std::string q) {
        bool visited[n] = {false};
        int node1, node2;
        std::istringstream iss(q);
        iss >> node1 >> node2;
        visited[0] = true;
        return find(node1, node2, adj);
    }
    int find(int node1, int node2, std::vector<std::vector<int>> adj) {
        if (node1 == node2) return node1;
        for (int i = 0; i < adj[node1].size(); i++) {
            if (adj[node1][i] != -1 && !visited[adj[node1][i]]) {
                visited[adj[node1][i]] = true;
                if (adj[adj[node1][i]].size() > 1 || adj[node2].size() > 1) {
                    return -1;
                }
                if (find(adj[node1][i], node2, adj) != -1) return adj[node1][i];
            }
        }
        return -2;
    }
};

int main() {
    int T = 1;
    while (T--) {
        int n;
        std::vector<std::vector<int>> adj;
        std::string q;
        std::cin >> n;
        for (int i = 0; i < n; i++) {
            adj.push_back(std::vector<int>(n, -1));
        }
        for (int i = 0; i < n - 1; i++) {
            int u, v;
            std::cin >> u >> v;
            adj[u][v] = adj[v][u] = i;
        }
        std::cin >> q;
        Solution solution;
        int ans = solution.lca(n, adj, q);
        if (ans != -2) {
            std::cout << ans << std::endl;
        } else {
            std::cout << -1 << std::endl;
        }
    }
    return 0;
}
